<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1"><?=e($invoice['invoice_number'])?></h1><p class="text-muted mb-0"><?=e($invoice['display_name'])?> · <?=e($invoice['status'])?></p></div><div class="d-flex gap-2"><form method="post" action="/portal/invoices/<?=$invoice['id']?>/pdf"><?=csrf_field()?><button class="btn btn-outline-secondary"><i class="fa-solid fa-file-pdf"></i> Generate PDF</button></form><form method="post" action="/portal/invoices/<?=$invoice['id']?>/send"><?=csrf_field()?><button class="btn btn-primary"><i class="fa-solid fa-paper-plane"></i> Send Invoice</button></form></div></div><div class="row g-4"><div class="col-lg-8"><div class="card card-body printable"><div class="d-flex justify-content-between"><img src="<?=asset('img/logo-primary.png')?>" style="max-width:300px" alt="Rock Bluffs"><div class="text-end"><h2 class="h4">INVOICE</h2><strong><?=e($invoice['invoice_number'])?></strong><br>Issued <?=e($invoice['issue_date'])?><br>Due <?=e($invoice['due_date'])?></div></div><hr><div class="row mb-4"><div class="col"><strong>Bill to</strong><br><?=e($invoice['display_name'])?><br><?=e($invoice['email'])?><br><?=e($invoice['phone'])?></div><div class="col text-end"><strong>Job</strong><br><?=e($invoice['job_number'])?><br><?=e($invoice['service_summary'])?></div></div><table class="table"><tr><td><?=e($invoice['service_summary']?:'Exterior services')?></td><td class="text-end"><?=money($invoice['subtotal'])?></td></tr><tr><th class="text-end">Tax</th><td class="text-end"><?=money($invoice['tax_amount'])?></td></tr><tr><th class="text-end fs-5">Total</th><th class="text-end fs-5"><?=money($invoice['total'])?></th></tr><tr><th class="text-end">Balance due</th><th class="text-end"><?=money($invoice['balance_due'])?></th></tr></table></div><?php if($documents):?><div class="portal-card p-4 mt-4 document-list"><h2 class="h5">Generated documents</h2><?php foreach($documents as $doc):?><div class="d-flex justify-content-between border-bottom py-2"><a href="/portal/documents/<?=e($doc['id'])?>"><i class="fa-solid fa-file-pdf me-2"></i><?=e($doc['original_name'])?></a><span class="badge text-bg-<?=$doc['storage_status']==='uploaded'?'success':'secondary'?>"><?=e($doc['storage_status'])?></span></div><?php endforeach?></div><?php endif?></div><div class="col-lg-4"><div class="card card-body mb-4"><h2 class="h5">Record payment</h2><form method="post" action="/portal/invoices/<?=$invoice['id']?>/payment"><?=csrf_field()?><div class="mb-3"><label class="form-label">Amount</label><input type="number" step="0.01" required name="amount" class="form-control" value="<?=e($invoice['balance_due'])?>"></div><div class="mb-3"><label class="form-label">Method</label><select name="method" class="form-select"><option>cash</option><option>check</option><option>card</option><option>ach</option><option>other</option></select></div><div class="mb-3"><label class="form-label">Reference</label><input name="reference" class="form-control"></div><button class="btn btn-success w-100">Record Payment</button></form></div><div class="card card-body mb-4"><h2 class="h5">Payments</h2><?php foreach($payments as $p):?><div class="d-flex justify-content-between border-bottom py-2"><span><?=e($p['method'])?><br><small class="text-muted"><?=e($p['received_at'])?></small></span><strong><?=money($p['amount'])?></strong></div><?php endforeach;if(!$payments):?><p class="text-muted mb-0">No payments recorded.</p><?php endif?></div><?php if($paymentSessions):?><div class="card card-body"><h2 class="h5">Online checkout</h2><?php foreach($paymentSessions as $ps):?><div class="border-bottom py-2"><span class="badge text-bg-<?=$ps['status']==='paid'?'success':'secondary'?>"><?=e($ps['status'])?></span> <?=money($ps['amount'])?><br><small class="text-muted"><?=e($ps['created_at'])?></small></div><?php endforeach?></div><?php endif?></div></div>
